# Check if running as root
if [ "$EUID" -ne 0 ]; then
  echo "Please run as root"
  exit 1
fi

# Kill application process if running
echo "Stopping Microsoft 365 Copilot if running..."
pkill -f "Microsoft 365 Copilot" 2>/dev/null || true

# Kill application with bundle ID com.microsoft.autoupdate2 if running
echo "Stopping application with bundle ID com.microsoft.autoupdate2 if running..."
killall -9 "com.microsoft.autoupdate2" 2>/dev/null || true

# Remove $HOME/Library/Application Scripts/com.microsoft.m365copilot
echo "Removing $HOME/Library/Application Scripts/com.microsoft.m365copilot..."
if [ -d "$HOME/Library/Application Scripts/com.microsoft.m365copilot" ]; then
    rm -rf "$HOME/Library/Application Scripts/com.microsoft.m365copilot" 2>/dev/null || true
elif [ -f "$HOME/Library/Application Scripts/com.microsoft.m365copilot" ]; then
