fi

# Remove $HOME/Library/Containers/com.microsoft.m365copilot
echo "Removing $HOME/Library/Containers/com.microsoft.m365copilot..."
if [ -d "$HOME/Library/Containers/com.microsoft.m365copilot" ]; then
